"""
mkt-christ commentary — Psalms 78–79
Run: python3 scripts/zc-christ-psalms-78-79.py

Key NT connections:
  Ps78:2   → Matt 13:35 (direct — parables fulfill Scripture)
  Ps78:13  → 1 Cor 10:1-2 (type — sea crossing as baptism)
  Ps78:15-16 → 1 Cor 10:4 (type — rock was Christ)
  Ps78:17-18 → 1 Cor 10:9 (type — testing Christ in wilderness)
  Ps78:24  → John 6:31-35 (direct — manna / true bread from heaven)
  Ps78:25  → John 6:49-51 (direct — bread of angels surpassed by Son)
  Ps78:52  → John 10:11 (shadow — Good Shepherd)
  Ps78:70-72 → Acts 13:22-23 (shadow — David chosen to shepherd)
  Ps79:6   → 2 Thess 1:8 (shadow — wrath on those who do not know God)
  Ps79:9   → Rom 3:25-26 (direct — atonement for God's name/glory)
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / "data" / "commentary" / source / f"{book}.json"
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / "data" / "commentary" / source / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f"  wrote {p.relative_to(ROOT)}")

def merge_comm(existing, new_data):
    # INTENT: merge without overwriting any verse already present in existing
    # CHANGE? Do not alter the guard; concurrent agents depend on append-only behavior
    # VERIFY: run twice; second run should report identical byte count for psalms.json
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEW_DATA = {"78": {"1": "<p><span class=\"level\">shadow</span> <em>Give ear, O my people, to my teaching; incline your ears to the words of my mouth!</em> The teacher who calls Israel to hear — Christ the supreme teacher who surpasses Moses: <em>you have heard it was said to those of old... but I say to you</em> (Matt 5:21-22). He gathers his people and commands them to hear, as the one whose word is spirit and life (John 6:63).</p>", "2": "<p><span class=\"level\">direct</span> <em>I will open my mouth in a parable; I will utter dark sayings from of old,</em> Matthew 13:35 quotes this verse explicitly as the fulfillment of Christ's parabolic teaching: <em>This was to fulfill what was spoken by the prophet: I will open my mouth in parables; I will utter what has been hidden since the foundation of the world.</em> Christ's entire parable ministry is the fulfillment of Psalm 78:2.</p>", "3": "<p><span class=\"level\">shadow</span> <em>things that we have heard and known, that our fathers have told us.</em> The transmission of covenant memory from fathers to children reaches its climax in the apostolic witness: <em>that which we have seen and heard we proclaim also to you</em> (1 John 1:3). Christ is the content of the tradition — the one to whom all the fathers' testimony pointed (Luke 24:27).</p>", "4": "<p><span class=\"level\">theme</span> <em>We will not hide them from their children, but tell to the coming generation the glorious deeds of the LORD, and his might, and the wonders that he has done.</em> The Great Commission is this imperative in its fullest form: <em>go and make disciples of all nations... teaching them to observe all that I have commanded you</em> (Matt 28:19-20). The glorious deeds of the LORD are now centered on Christ's death and resurrection.</p>", "5": "<p><span class=\"level\">shadow</span> <em>He established a testimony in Jacob and appointed a law in Israel, which he commanded our fathers to teach to their children,</em> The law appointed in Israel is fulfilled and internalized by Christ: <em>I have not come to abolish the Law or the Prophets but to fulfill them</em> (Matt 5:17). The new covenant writes the law on the heart (Jer 31:33; Heb 8:10) — Christ is the mediator of this interior Torah.</p>", "6": "<p><span class=\"level\">theme</span> <em>that the next generation might know them, the children yet unborn, and arise and tell them to their children,</em> The multigenerational transmission of faith — now centered on Christ: <em>you shall be my witnesses in Jerusalem and in all Judea and Samaria, and to the end of the earth</em> (Acts 1:8). Each generation's telling of the glorious deeds is the telling of Jesus crucified and risen.</p>", "7": "<p><span class=\"level\">theme</span> <em>so that they should set their hope in God and not forget the works of God, but keep his commandments;</em> Hope set in God is hope in Christ — <em>Christ Jesus our hope</em> (1 Tim 1:1). The works of God not to be forgotten are now the works of Christ: his healings, his teachings, and supremely his resurrection. Keeping his commandments is the mark of love for him (John 14:15).</p>", "8": "<p><span class=\"level\">shadow</span> <em>and that they should not be like their fathers, a stubborn and rebellious generation, a generation whose heart was not steadfast, whose spirit was not faithful to God.</em> The warning against Israel's pattern of unfaithfulness is answered by Christ the perfectly faithful Israelite — <em>obedient even to death</em> (Phil 2:8). He is the true Israel who never wavered; those in him are empowered not to be like their fathers (Heb 3:7-11).</p>", "9": "<p><span class=\"level\">type</span> <em>The Ephraimites, armed with the bow, turned back on the day of battle.</em> Ephraim's cowardly turning back in battle — the disciples who fled at Gethsemane (Matt 26:56 — <em>all the disciples left him and fled</em>) repeat the pattern. But Christ does not turn back; he faces the battle alone, the faithful Israelite who does not flee.</p>", "10": "<p><span class=\"level\">type</span> <em>They did not keep God's covenant, but refused to walk according to his law.</em> Israel's covenant-breaking is the backdrop against which Christ's covenant faithfulness blazes. He is the new covenant mediator (Heb 9:15) precisely because he kept what Israel broke — his obedience becomes the righteousness imputed to covenant-breakers who believe in him.</p>", "11": "<p><span class=\"level\">type</span> <em>They forgot his works and the wonders that he had shown them.</em> The forgetting of God's works is the spiritual amnesia Christ diagnoses and heals: <em>do you not yet understand or remember the five loaves for the five thousand?</em> (Matt 16:9). He who performs signs is himself the sign the unbelieving heart forgets — and the Spirit comes to remind and teach (John 14:26).</p>", "12": "<p><span class=\"level\">type</span> <em>In the sight of their fathers he performed wonders in the land of Egypt, in the fields of Zoan.</em> The Exodus wonders — Paul in 1 Cor 10:1-4 reads the entire Exodus as typological, with Christ present throughout. The pattern of wonders in Egypt prefigures the sign-ministry of Christ (John 2:11 — <em>the first of his signs... and manifested his glory</em>).</p>", "13": "<p><span class=\"level\">type</span> <em>He divided the sea and let them pass through it, and made the waters stand like a heap.</em> The sea-crossing as baptism: <em>all were baptized into Moses in the cloud and in the sea</em> (1 Cor 10:1-2). Christ fulfills what the Red Sea crossing typified — passing through the waters of death and coming out on the other side in resurrection life. Baptism into Christ's death and resurrection (Rom 6:3-4) is the antitype.</p>", "14": "<p><span class=\"level\">type</span> <em>In the daytime he led them with a cloud, and all the night with a fiery light.</em> The pillar of cloud and fire — the divine presence guiding Israel — is the pattern of the Spirit Christ sends to guide his people: <em>when the Spirit of truth comes, he will guide you into all the truth</em> (John 16:13). The Spirit at Pentecost comes as tongues of fire (Acts 2:3), the fiery light now inhabiting God's people.</p>", "15": "<p><span class=\"level\">type</span> <em>He split rocks in the wilderness and gave them drink abundantly as from the deep.</em> Paul identifies the rock explicitly: <em>they drank from the spiritual Rock that followed them, and the Rock was Christ</em> (1 Cor 10:4). The water from the split rock is the life-giving water Christ provides — <em>if anyone thirsts, let him come to me and drink</em> (John 7:37). The wilderness rock split is a type of Christ's body broken to release living water.</p>", "16": "<p><span class=\"level\">type</span> <em>He made streams come out of the rock and caused waters to flow down like rivers.</em> Streams from the rock — flowing into the new covenant: <em>out of his heart will flow rivers of living water</em> (John 7:38 — Jesus applies the imagery to the Spirit given through himself). The rock struck in the wilderness flows abundantly; the pierced side of Christ flows with blood and water (John 19:34).</p>", "17": "<p><span class=\"level\">type</span> <em>Yet they sinned still more against him, rebelling against the Most High in the desert.</em> The wilderness rebellion as pattern and warning — Paul applies it directly to Christians tempted to repeat Israel's failures: <em>we must not put Christ to the test, as some of them did and were destroyed by serpents</em> (1 Cor 10:9). The rebellion against the Most High is now rebellion against Christ.</p>", "18": "<p><span class=\"level\">type</span> <em>They tested God in their heart by demanding the food they craved.</em> Testing God by demanding food — the temptation Christ refused in the wilderness: <em>man shall not live by bread alone, but by every word that comes from the mouth of God</em> (Matt 4:4). He who is the bread of life (John 6:35) refused to turn stones to bread, overcoming what Israel failed.</p>", "19": "<p><span class=\"level\">type</span> <em>They spoke against God, saying, Can God spread a table in the wilderness?</em> The question of wilderness provision recurs in John 6:31 — the crowd asks, <em>What sign do you do?... Our fathers ate the manna in the wilderness.</em> They too question whether God can provide — and Jesus answers by declaring himself the true bread from heaven (John 6:32-35). Can God spread a table? Christ is that table.</p>", "20": "<p><span class=\"level\">type</span> <em>He struck the rock so that water gushed out and streams overflowed. Can he also give bread, or provide meat for his people?</em> The doubting question — answered by the feeding miracles. Christ feeds 5,000 (Matt 14:13-21) and 4,000 (Matt 15:32-38) in the wilderness setting, demonstrating that the one who gave water from the rock can also provide bread and meat, and is himself the bread that satisfies forever (John 6:35).</p>", "21": "<p><span class=\"level\">type</span> <em>Therefore, when the LORD heard, he was full of wrath; a fire was kindled against Jacob; his anger rose against Israel,</em> Divine wrath in the wilderness — the backdrop for understanding the atonement. Christ bears the wrath that rose against rebellious Israel: <em>Christ redeemed us from the curse of the law by becoming a curse for us</em> (Gal 3:13). The fire kindled against Jacob was ultimately quenched in Christ.</p>", "22": "<p><span class=\"level\">type</span> <em>because they did not believe in God and did not trust his saving power.</em> Unbelief as the root of Israel's failure — and the sin Christ came to address. The Johannine refrain: <em>this is the work of God, that you believe in him whom he has sent</em> (John 6:29). Faith in Christ is the antidote to the unbelief that caused Israel to perish in the wilderness (Heb 3:19).</p>", "23": "<p><span class=\"level\">type</span> <em>Yet he commanded the skies above and opened the doors of heaven,</em> The opened doors of heaven — fulfilled at Christ's baptism: <em>the heavens were opened to him</em> (Matt 3:16). The same opening that released manna in the wilderness is the opening at the Jordan that inaugurates Christ's ministry and declares him the beloved Son.</p>", "24": "<p><span class=\"level\">direct</span> <em>and he rained down on them manna to eat and gave them the grain of heaven.</em> John 6:31 cites this verse as the crowd's justification for demanding a sign: <em>He gave them bread from heaven to eat.</em> Jesus responds: <em>it was not Moses who gave you the bread from heaven, but my Father gives you the true bread from heaven. For the bread of God is he who comes down from heaven and gives life to the world</em> (John 6:32-33). The manna of Ps 78:24 is the direct type Christ claims to fulfill.</p>", "25": "<p><span class=\"level\">direct</span> <em>Man ate of the bread of the angels; he sent them food in abundance.</em> Jesus cites the abundance of the manna to make a contrast: <em>Your fathers ate the manna in the wilderness, and they died... I am the living bread that came down from heaven. If anyone eats of this bread, he will live forever</em> (John 6:49-51). The bread of angels in abundance is surpassed by the bread of the Son of God who gives not physical life but eternal life.</p>", "26": "<p><span class=\"level\">type</span> <em>He caused the east wind to blow in the heavens, and by his power he led out the south wind;</em> Divine control over winds — fulfilled in Christ who commands the winds: <em>he rebuked the wind and the raging waves, and they ceased</em> (Luke 8:24). The disciples asked, <em>Who then is this?</em> — the answer is the one who causes east and south winds to blow, the creator of weather now present in a boat.</p>", "27": "<p><span class=\"level\">type</span> <em>he rained meat on them like dust, winged birds like the sand of the seas;</em> Abundance of provision — the eschatological feast theme. Christ at the feeding miracles provides from apparent scarcity; at the last supper he provides his own body and blood. The birds raining from heaven prefigure the Spirit's abundant gifts poured out through Christ at Pentecost.</p>", "28": "<p><span class=\"level\">type</span> <em>he let them fall in the midst of their camp, all around their dwellings.</em> God's provision surrounding the camp — the Spirit surrounding the church: <em>the Spirit of him who raised Jesus from the dead dwells in you</em> (Rom 8:11). God's provision in Christ comes not from outside but from within, dwelling in the midst of his people.</p>", "29": "<p><span class=\"level\">type</span> <em>And they ate and were well filled, for he gave them what they craved.</em> Satisfaction of craving — but the wilderness generation craved physical food, not the bread of life. Christ gives what the soul truly craves: <em>blessed are those who hunger and thirst for righteousness, for they shall be satisfied</em> (Matt 5:6). He satisfies the deepest hunger with himself.</p>", "30": "<p><span class=\"level\">type</span> <em>But before they had satisfied their craving, while the food was still in their mouths,</em> The insatiability of fleshly craving — the contrast with Christ who truly satisfies: <em>everyone who drinks of this water will be thirsty again, but whoever drinks of the water that I will give him will never be thirsty again</em> (John 4:13-14). The manna could not satisfy permanently; Christ alone does.</p>", "31": "<p><span class=\"level\">type</span> <em>the anger of God rose against them, and he killed the strongest of them and laid low the young men of Israel.</em> Divine judgment in the wilderness — the death of the strong as warning. Paul applies this pattern to the Corinthian church as a warning to those who presume on grace (1 Cor 10:5-11). The death of the strong in the wilderness is the type; the exhortation to those in Christ is not to fall by the same unbelief.</p>", "32": "<p><span class=\"level\">type</span> <em>In spite of all this, they sinned still more, and did not believe in his wondrous works.</em> Persistent unbelief despite wonders — the pattern that reaches its climax in those who saw Christ's miracles and did not believe (John 12:37 — <em>though he had done so many signs before them, they still did not believe in him</em>). The hardening foretold in Isaiah (John 12:38-41) is the same pattern Israel displayed in the wilderness.</p>", "33": "<p><span class=\"level\">type</span> <em>So he made their days vanish like a breath, and their years in terror.</em> The vanishing of days in the wilderness — the generation that perished without entering the land. Hebrews uses this as the supreme warning: <em>take care, brothers, lest there be in any of you an evil, unbelieving heart, leading you to fall away from the living God</em> (Heb 3:12). Christ is the rest the wilderness generation never entered (Heb 4:1-11).</p>", "34": "<p><span class=\"level\">type</span> <em>When he killed them, they sought him; they repented and sought God earnestly.</em> Repentance under judgment — the pattern of genuine turning. Christ calls for this repentance: <em>unless you repent, you will all likewise perish</em> (Luke 13:3). The seeking under pressure is imperfect; Christ seeks those who turn to him permanently — the seeking shepherd who leaves the ninety-nine (Luke 15:4).</p>", "35": "<p><span class=\"level\">shadow</span> <em>They remembered that God was their rock, the Most High God their redeemer.</em> Rock and Redeemer — both titles belonging to Christ. The rock is Christ (1 Cor 10:4); the Redeemer is Christ: <em>in him we have redemption through his blood, the forgiveness of our trespasses</em> (Eph 1:7). When they remembered God as rock and redeemer, they were remembering the one who would be incarnate as Jesus of Nazareth.</p>", "36": "<p><span class=\"level\">type</span> <em>But they flattered him with their mouths; they lied to him with their tongues.</em> Flattery concealing unbelief — the very pattern the religious leaders displayed before Christ. They approached him with empty honor (Matt 15:8 — <em>this people honors me with their lips, but their heart is far from me</em>), testing him with clever questions while plotting his death. Mouth-honor masking rejection.</p>", "37": "<p><span class=\"level\">type</span> <em>Their heart was not steadfast toward him; they were not faithful to his covenant.</em> The unfaithful heart — the diagnosis of the old covenant problem that the new covenant addresses: <em>I will give you a new heart, and a new spirit I will put within you</em> (Ezek 36:26). Christ is the mediator of the new covenant (Heb 9:15) who creates the steadfast heart Israel lacked.</p>", "38": "<p><span class=\"level\">shadow</span> <em>Yet he, being compassionate, atoned for their iniquity and did not destroy them; he restrained his anger often and did not stir up all his wrath.</em> God's atoning compassion — the impulse that drives the Incarnation. The atonement restrained since Eden finds its full expression in Christ: <em>God was in Christ reconciling the world to himself, not counting their trespasses against them</em> (2 Cor 5:19). Every act of divine patience in the wilderness was an advance on the cross.</p>", "39": "<p><span class=\"level\">shadow</span> <em>He remembered that they were but flesh, a wind that passes and comes not again.</em> God's remembering of human frailty is the compassion that drives the Incarnation: <em>since the children share in flesh and blood, he himself likewise partook of the same things</em> (Heb 2:14). Christ became flesh and dwelt among us — God remembering that we are flesh by entering that flesh himself.</p>", "40": "<p><span class=\"level\">type</span> <em>How often they rebelled against him in the wilderness and grieved him in the desert!</em> Grieving the Spirit — the pattern Paul warns against: <em>do not grieve the Holy Spirit of God</em> (Eph 4:30). The wilderness rebellion that grieved God is the backdrop for understanding how Christ's people must not grieve the Spirit he has sent. The rebellion in the wilderness is now the potential rebellion in the church.</p>", "41": "<p><span class=\"level\">type</span> <em>They tested God again and again and provoked the Holy One of Israel.</em> Testing God in the wilderness — Paul applies this to testing Christ: <em>we must not put Christ to the test, as some of them did and were destroyed by serpents</em> (1 Cor 10:9). The Holy One of Israel is Christ himself — the one whose name Isaiah declared and John applied to Jesus (John 12:41 — Isaiah saw Christ's glory).</p>", "42": "<p><span class=\"level\">type</span> <em>They did not remember his power — the day when he redeemed them from the foe,</em> Forgetting the redemption — the failure that Christ's Supper was instituted to prevent: <em>do this in remembrance of me</em> (1 Cor 11:24-25). The Lord's Supper is the covenant meal that keeps the redemption in the community's memory, so that the church does not forget as the wilderness generation did.</p>", "43": "<p><span class=\"level\">type</span> <em>when he performed his signs in Egypt and his marvels in the fields of Zoan.</em> The signs in Egypt — prefiguring Christ's sign ministry: <em>Jesus did many other signs in the presence of the disciples, which are not written in this book; but these are written so that you may believe that Jesus is the Christ</em> (John 20:30-31). John's Gospel is structured around signs that echo the Exodus pattern.</p>", "44": "<p><span class=\"level\">type</span> <em>He turned their rivers to blood, so that they could not drink of their streams.</em> The plague of blood — a type of the covenant blood of Christ. Where the plague turned water to blood and brought death, Christ turns the water of his covenant to the life-giving blood of the new covenant (Matt 26:28 — <em>my blood of the covenant, which is poured out for many for the forgiveness of sins</em>).</p>", "45": "<p><span class=\"level\">type</span> <em>He sent among them swarms of flies, which devoured them, and frogs, which destroyed them.</em> The plagues of flies and frogs — the judgment on Egypt that foreshadows final judgment. Christ speaks of final judgment with equal severity: <em>it is better for you to enter the kingdom of God with one eye than with two eyes to be thrown into hell</em> (Mark 9:47). The plagues of Egypt are the shadow of the wrath Christ absorbs and the judgment he will finally administer.</p>", "46": "<p><span class=\"level\">type</span> <em>He gave their crops to the destroying locust and the fruit of their labor to the locust.</em> The locust plague destroying the fruit of labor — the judgment on Egypt pointing to the eschatological locusts of Rev 9:1-11. Christ warns of the destruction of the fruitless tree (Matt 3:10; 21:19) and the parable of the vineyard taken from those who bear no fruit (Matt 21:41).</p>", "47": "<p><span class=\"level\">type</span> <em>He destroyed their vines with hail and their sycamore trees with frost.</em> The hail destroying vines and trees — prefiguring the eschatological hail of Rev 8:7; 16:21. Christ's parable of the vine (John 15:1-8) shows him as the true vine; those not abiding in him are like the vines destroyed by hail — cut off and thrown into the fire (John 15:6).</p>", "48": "<p><span class=\"level\">type</span> <em>He gave over their cattle to the hail and their flocks to thunderbolts.</em> God giving over — the language of Rom 1:24-28 (God gave them over to their desires). The plagues are the pattern of divine judgment that Paul analyzes theologically. Christ's death is the ultimate giving-over: <em>he who did not spare his own Son but gave him up for us all</em> (Rom 8:32) — a giving-over of love instead of judgment.</p>", "49": "<p><span class=\"level\">type</span> <em>He let loose on them his burning anger, wrath, indignation, and distress, a company of destroying angels.</em> The burning anger loosed on Egypt — the same categories of wrath that Christ absorbs at the cross (Rom 3:25 — propitiation; Gal 3:13 — bearing the curse). The destroying angels are restrained from the church by the blood of Christ, the Passover Lamb (1 Cor 5:7).</p>", "50": "<p><span class=\"level\">type</span> <em>He made a path for his anger; he did not spare them from death, but gave their lives over to the plague.</em> Not sparing from death — contrasted with Christ: <em>he who did not spare his own Son but gave him up for us all, how will he not also with him graciously give us all things?</em> (Rom 8:32). God did not spare Egypt; he did not spare his own Son; but in not sparing Christ he now spares all who are in him.</p>", "51": "<p><span class=\"level\">type</span> <em>He struck down every firstborn in Egypt, the firstfruits of their strength in the tents of Ham.</em> The death of the firstborn — the supreme Passover plague. Christ is the Passover Lamb who prevents the final firstborn-death from striking those sheltered by his blood (1 Cor 5:7). He is himself the firstborn: <em>the firstborn of all creation</em> (Col 1:15), <em>the firstborn from the dead</em> (Col 1:18).</p>", "52": "<p><span class=\"level\">shadow</span> <em>Then he led out his people like sheep and guided them in the wilderness like a flock.</em> God leading his people as sheep — fulfilled in Christ the Good Shepherd: <em>I am the good shepherd. The good shepherd lays down his life for the sheep</em> (John 10:11). The shepherd-king who leads Israel through the wilderness is the pattern Christ embodies; he guides his flock through the wilderness of this age.</p>", "53": "<p><span class=\"level\">shadow</span> <em>He led them in safety, so that they were not afraid, but the sea overwhelmed their enemies.</em> Safe passage through danger as the enemies drown — the pattern of baptism (1 Cor 10:1-2; 1 Pet 3:20-21). Christ leads his people through the waters of death safely; their enemies (sin, death, the devil) are overwhelmed as Pharaoh's army was drowned. Those in Christ need not fear the waters.</p>", "54": "<p><span class=\"level\">shadow</span> <em>And he brought them to his holy land, the mountain that his right hand had won.</em> The holy land won by God's right hand — the new creation won by Christ's right hand (Heb 1:3 — <em>he sat down at the right hand of the Majesty on high</em>). The inheritance the Exodus generation entered is the type of the eternal inheritance secured by Christ (Heb 9:15; 1 Pet 1:4).</p>", "55": "<p><span class=\"level\">type</span> <em>He drove out nations before them; he apportioned them for a possession and settled the tribes of Israel in their tents.</em> The conquest as type — fulfilled eschatologically in Christ's victory over the principalities and powers (Col 2:15) and the ultimate settlement of God's people in the new creation (Rev 21:3 — <em>Behold, the dwelling place of God is with man</em>).</p>", "56": "<p><span class=\"level\">type</span> <em>Yet they tested and rebelled against the Most High God and did not keep his testimonies,</em> Rebellion after settlement — the pattern of spiritual complacency. Hebrews warns the church against repeating this: <em>see to it that no one fails to obtain the grace of God</em> (Heb 12:15). Christ is the one who never rebelled, whose testimony was always kept — and in whom the rebellious find forgiveness.</p>", "57": "<p><span class=\"level\">type</span> <em>but turned away and acted treacherously like their fathers; they twisted like a deceitful bow.</em> The twisted, unreliable bow — Israel's inconsistency. Contrasted with Christ who is the same yesterday, today, and forever (Heb 13:8). He is the faithful witness (Rev 1:5), the one who does not twist or turn, whose yes is always yes (2 Cor 1:20).</p>", "58": "<p><span class=\"level\">type</span> <em>For they provoked him to anger with their high places; they moved him to jealousy with their idols.</em> Idolatry provoking divine jealousy — Christ cleanses the temple as the act of divine jealousy for God's house (John 2:17 — <em>zeal for your house has consumed me</em>). The true God tolerates no rival; Christ is the true image of the invisible God (Col 1:15) that replaces all idols.</p>", "59": "<p><span class=\"level\">type</span> <em>When God heard, he was full of wrath, and he utterly rejected Israel.</em> Divine rejection — not the final word in Israel's story or the church's. Paul wrestles with this: <em>I ask, then, has God rejected his people? By no means!</em> (Rom 11:1). The apparent rejection becomes the occasion for the Gentile mission; the final reconciliation comes through Christ (Rom 11:25-26).</p>", "60": "<p><span class=\"level\">shadow</span> <em>He forsook his dwelling at Shiloh, the tent where he dwelt among mankind,</em> The forsaking of Shiloh — God departing from the sanctuary. Christ predicts the same departure from Jerusalem: <em>See, your house is left to you desolate</em> (Matt 23:38; Luke 13:35). But he is himself the new sanctuary — <em>destroy this temple, and in three days I will raise it up</em> (John 2:19). God does not ultimately abandon his dwelling; he moves it into Christ.</p>", "61": "<p><span class=\"level\">shadow</span> <em>and delivered his power to captivity, his glory to the hand of the foe.</em> The glory delivered to the enemy — the cross as God's apparent defeat. Christ is delivered into the hands of sinners (Matt 26:45); God's power is handed over to crucifixion. But the delivery is the strategy: <em>the weakness of God is stronger than men</em> (1 Cor 1:25). The glory delivered to the foe is the glory that rises from the tomb.</p>", "62": "<p><span class=\"level\">shadow</span> <em>He gave his people over to the sword and vented his wrath on his heritage.</em> Given over to the sword — the language of the atonement: <em>he who did not spare his own Son but gave him up for us all</em> (Rom 8:32). Christ is the ultimate <em>given over to the sword</em> — the one on whom divine wrath is vented so that his heritage need not face it permanently.</p>", "63": "<p><span class=\"level\">type</span> <em>Fire devoured his young men, and his young women had no marriage song.</em> The devastation of the youth — the tragedy of judgment. Christ mourns over Jerusalem which faces this judgment (Luke 19:41-44; Luke 23:27-31 — <em>daughters of Jerusalem, do not weep for me, but weep for yourselves and your children</em>). He warns of the coming fire that will devour the faithless city.</p>", "64": "<p><span class=\"level\">type</span> <em>His priests fell by the sword, and his widows made no lamentation.</em> Priests falling by the sword — the reversal of the priestly order. Christ is the new high priest (Heb 4:14) who does not fall by the sword but through his own willing self-offering, and who replaces the fallen priesthood with himself as the eternal mediator (Heb 7:24 — <em>he holds his priesthood permanently</em>).</p>", "65": "<p><span class=\"level\">shadow</span> <em>Then the Lord awoke as from sleep, like a strong man shouting because of wine.</em> God awakening — the resurrection as God's waking to decisive action. The sleeping Lord who suddenly rises to act is the image of God raising Christ from the dead: <em>God raised him up, loosing the pangs of death</em> (Acts 2:24). The strong man who awakens is the risen Christ, <em>declared to be the Son of God in power</em> (Rom 1:4).</p>", "66": "<p><span class=\"level\">shadow</span> <em>And he put his adversaries to rout; he put them to everlasting shame.</em> The adversaries put to everlasting shame — the principalities and powers defeated at the cross: <em>he disarmed the rulers and authorities and put them to open shame, by triumphing over them in him</em> (Col 2:15). The everlasting shame is the defeat of death, confirmed at the resurrection and made final at the parousia.</p>", "67": "<p><span class=\"level\">shadow</span> <em>He rejected the tent of Joseph; he did not choose the tribe of Ephraim,</em> The rejection of Ephraim in favor of Judah — the divine election that bypasses the expected and chooses the surprising. God's election operates through unexpected channels, fulfilled ultimately in Christ who comes from Judah, the tribe of the lion: <em>the Lion of the tribe of Judah, the Root of David, has conquered</em> (Rev 5:5).</p>", "68": "<p><span class=\"level\">shadow</span> <em>but he chose the tribe of Judah, Mount Zion, which he loves.</em> The election of Judah and Zion — Christ comes from Judah (Matt 1:2-3; Heb 7:14 — <em>our Lord was descended from Judah</em>) and is the cornerstone of Zion (1 Pet 2:6, citing Isa 28:16). The love of Zion is the love that sent the Son: <em>God so loved the world that he gave his only Son</em> (John 3:16).</p>", "69": "<p><span class=\"level\">shadow</span> <em>He built his sanctuary like the high heavens, like the earth, which he has founded forever.</em> The sanctuary built like the heavens — fulfilled in Christ's body as the new temple (John 2:21) and in the heavenly sanctuary he entered with his own blood (Heb 9:12). The eternal founding is the eternal nature of Christ's priestly work: <em>he holds his priesthood permanently, because he continues forever</em> (Heb 7:24).</p>", "70": "<p><span class=\"level\">shadow</span> <em>He chose David his servant and took him from the sheepfolds;</em> David chosen from the sheepfolds — the pattern Christ fulfills as the true David: <em>Jesus Christ, the son of David</em> (Matt 1:1). The shepherd-king who tends sheep and is chosen to rule Israel is the type of the Good Shepherd who lays down his life for the sheep and is exalted as King of kings (Rev 17:14).</p>", "71": "<p><span class=\"level\">shadow</span> <em>from following the nursing ewes he brought him to shepherd Jacob his people, Israel his inheritance.</em> David brought from following nursing ewes to shepherd Israel — Christ's transition from Nazareth to messianic ministry: the carpenter's son (Matt 13:55) becomes the shepherd of all Israel. His ministry to <em>the lost sheep of the house of Israel</em> (Matt 15:24) is the literal fulfillment before the Gentile mission opens.</p>", "72": "<p><span class=\"level\">shadow</span> <em>With upright heart he shepherded them and guided them with his skillful hand.</em> The upright shepherd with a skillful hand — the Good Shepherd who tends his flock with perfect integrity. Christ has no guile; he is the righteous shepherd (1 Pet 2:22 — <em>no sin was found in his mouth</em>) who guides with wisdom born of perfect communion with the Father (John 10:15 — <em>I know my own and my own know me</em>).</p>"}, "79": {"1": "<p><span class=\"level\">shadow</span> <em>O God, the nations have come into your inheritance; they have defiled your holy temple; they have laid Jerusalem in ruins.</em> The defilement of the temple — Christ predicted precisely this: <em>you see all these, do you not? Truly, I say to you, there will not be left here one stone upon another that will not be thrown down</em> (Matt 24:2). The destruction of Jerusalem in AD 70 is the judgment he foresaw, weeping over the city that would not receive him (Luke 19:41-44).</p>", "2": "<p><span class=\"level\">shadow</span> <em>They have given the bodies of your servants to the birds of the heavens for food, the flesh of your faithful to the beasts of the earth.</em> The bodies given to birds — the imagery Revelation applies to the great eschatological battle: <em>Come, gather for the great supper of God, to eat the flesh of kings... and the flesh of all men</em> (Rev 19:17-18). The judgment fallen on Jerusalem becomes the type of final judgment on all who oppose the Lamb.</p>", "3": "<p><span class=\"level\">shadow</span> <em>They have poured out their blood like water all around Jerusalem, and there was no one to bury them.</em> Blood poured out around Jerusalem — the blood of the martyrs, and ultimately the blood of Christ shed in Jerusalem: <em>it cannot be that a prophet should perish away from Jerusalem</em> (Luke 13:33). His blood poured out is the blood of the new covenant (Matt 26:28) that gives meaning to all martyrs' blood.</p>", "4": "<p><span class=\"level\">shadow</span> <em>We have become a taunt to our neighbors, mocked and derided by those around us.</em> Taunt and derision — the experience of Christ and his church. The nations mock the suffering people of God; Christ was mocked supremely (Matt 27:39-44). Peter addresses this: <em>if you are insulted for the name of Christ, you are blessed, because the Spirit of glory and of God rests upon you</em> (1 Pet 4:14).</p>", "5": "<p><span class=\"level\">shadow</span> <em>How long, O LORD? Will you be angry forever? Will your jealousy burn like fire?</em> The <em>how long</em> of the martyrs — the cry under the altar in Revelation: <em>how long before you will judge and avenge our blood on those who dwell on the earth?</em> (Rev 6:10). Christ establishes the answer: <em>will not God give justice to his elect, who cry to him day and night?</em> (Luke 18:7). The <em>how long</em> is answered by the parousia.</p>", "6": "<p><span class=\"level\">shadow</span> <em>Pour out your anger on the nations that do not know you, and on the kingdoms that do not call upon your name!</em> The pouring out of wrath on those who do not know God — Paul's language in 2 Thess 1:8: <em>inflicting vengeance on those who do not know God and on those who do not obey the gospel of our Lord Jesus.</em> The judgment of the nations is now specifically tied to rejecting Christ and his gospel.</p>", "7": "<p><span class=\"level\">shadow</span> <em>For they have devoured Jacob and laid waste his habitation.</em> The devouring of Jacob — Israel scattered. But Christ promises the ultimate gathering: <em>he will send out his angels with a loud trumpet call, and they will gather his elect from the four winds, from one end of heaven to the other</em> (Matt 24:31). The scattered Jacob is gathered by the one who is the true Jacob, the Israel of God (Gal 6:16).</p>", "8": "<p><span class=\"level\">shadow</span> <em>Do not remember against us our former iniquities; let your compassion come speedily to meet us, for we are brought very low.</em> The plea for compassion to come speedily — the Incarnation itself. God's compassion coming to meet humanity brought very low is the Son of God born in a manger (Luke 2:7), taking on the lowliness of the human condition. He comes speedily to the one brought low; the parousia brings the final relief.</p>", "9": "<p><span class=\"level\">direct</span> <em>Help us, O God of our salvation, for the glory of your name; deliver us, and atone for our sins, for your name's sake!</em> Atonement for God's name's sake — the motive Paul identifies in Rom 3:25-26: God presented Christ as a propitiation <em>to show his righteousness</em> and to demonstrate that <em>he himself is just and the justifier of the one who has faith in Jesus.</em> The atonement vindicates God's glory and name while delivering sinners.</p>", "10": "<p><span class=\"level\">shadow</span> <em>Why should the nations say, Where is their God? Let the avenging of the outpoured blood of your servants be known among the nations before our eyes!</em> <em>Where is their God?</em> — the taunt directed at the crucified Jesus: <em>let God deliver him now, if he desires him</em> (Matt 27:43). The resurrection is God's public vindication — the avenging of the righteous one's blood made known among the nations through the apostolic proclamation (Acts 2:32-36).</p>", "11": "<p><span class=\"level\">shadow</span> <em>Let the groaning of the prisoner come before you; according to your great power, preserve those doomed to die!</em> The groaning prisoner preserved from death — Christ in the tomb, the one doomed to die by the sentence of Pilate. God's great power preserves him not by preventing death but by raising him through it. All who are doomed to die in Adam are preserved in Christ (1 Cor 15:22 — <em>in Christ shall all be made alive</em>).</p>", "12": "<p><span class=\"level\">shadow</span> <em>Return sevenfold into the lap of our neighbors the taunts with which they have taunted you, O Lord!</em> The sevenfold return of taunts — the divine vindication. Those who taunted God's people (and Christ) face the consequences of their mockery. Rev 18:6 uses similar language of judgment on Babylon: <em>pay her back double for her deeds.</em> The taunts against the crucified one return on those who refuse repentance.</p>", "13": "<p><span class=\"level\">shadow</span> <em>But we your people, the sheep of your pasture, will give thanks to you forever; from generation to generation we will recount your praise.</em> The sheep of your pasture — Christ's flock, who give thanks forever. The church's unending praise is grounded in the resurrection: <em>through him then let us continually offer up a sacrifice of praise to God, that is, the fruit of lips that acknowledge his name</em> (Heb 13:15). Generation after generation recounting God's praise is the church's mission until the parousia.</p>"}}

if __name__ == "__main__":
    book = "psalms"
    source = "mkt-christ"
    existing = load_comm(source, book)
    merge_comm(existing, NEW_DATA)
    save_comm(source, book, existing)
    for ch, vv in NEW_DATA.items():
        saved = existing.get(ch, {})
        missing = [v for v in vv if v not in saved]
        print(f"  ch {ch}: {len(vv)} entries, {len(missing)} missing after merge")
